// src/pages/cleaner/CleanerPortal.jsx
import React, { useRef, useState } from 'react';
import { useApp } from '../../App';
import { Sidebar } from '../../components/Sidebar';
import { ComplaintCard } from '../../components/ComplaintCard';
import { NotifBanner } from '../../components/UI';

export default function CleanerPortal() {
  const { complaints, uploadCleanerVerification } = useApp();
  const [tab, setTab] = useState('my_jobs');
  const [notif, setNotif] = useState(null);
  const fileInputRef = useRef({});

  // Sirf wahi tasks filter karein jo is specific cleaner department team ko hand-over kiye gaye hain
  const assignedJobs = complaints.filter(c => c.status === 'ASSIGNED_TO_CLEANER');

  const handleCaptureSubmit = async (complaintId, e) => {
    const file = e.target.files[0];
    if (file) {
      setNotif("Uploading live visual evidence string data...");
      await uploadCleanerVerification(complaintId, file);
      setNotif("Clean status dispatch submitted to Vendor registry validation panel!");
    }
  };

  return (
    <div style={{ display: 'flex', height: '100vh', fontFamily: 'system-ui,sans-serif', overflow: 'hidden' }}>
      <Sidebar title="Cleaner Force" subtitle="Ground Operations" 
        navItems={[{ key: 'my_jobs', icon: '🧹', label: 'My Orders' }]} 
        activeTab={tab} onTabChange={setTab}
        footerUser={{ initials: 'CF', name: 'Ground Force Team 1', role: 'Operator', avatarColor: '#4527A0' }} 
      />
      <div style={{ flex: 1, overflowY: 'auto', background: '#F7F9FC', padding: 22 }}>
        <div style={{ fontSize: 18, fontWeight: 800, marginBottom: 12 }}>Assigned Active Sweep Schedules</div>
        {notif && <NotifBanner msg={notif} type="amber" onDone={() => setNotif(null)} />}

        {assignedJobs.length === 0 ? (
          <div style={{ padding: 40, textAlign: 'center', background: '#fff', borderRadius: 12, border: '1px solid #DDE3E9', color: '#7A8FA6' }}>
            🦺 Standby state. No cleaning tracks redirected to your profile right now.
          </div>
        ) : (
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit,minmax(240px,1fr))', gap: 14 }}>
            {assignedJobs.map(c => (
              <ComplaintCard key={c.id} complaint={c} actions={
                <div style={{ width: '100%' }}>
                  <button onClick={() => fileInputRef.current[c.id].click()} style={{ width: '100%', background: '#2E7D32', color: '#fff', border: 'none', padding: '8px 12px', borderRadius: 8, fontSize: 12, fontWeight: 700, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6 }}>
                    📸 Capture Cleaned Area Photo
                  </button>
                  <input 
                    type="file" 
                    accept="image/*" 
                    capture="environment" // Mobile devices par direct environmental camera module push karega
                    ref={el => fileInputRef.current[c.id] = el}
                    onChange={(e) => handleCaptureSubmit(c.id, e)}
                    style={{ display: 'none' }} 
                  />
                </div>
              } />
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
